#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int *)a - *(int *)b);
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int nums[3];
        scanf("%d %d %d", &nums[0], &nums[1], &nums[2]);
        if (nums[0] == nums[1] || nums[0] == nums[2] || nums[1] == nums[2]) {
            printf("Error: The three integers in a single triplet are all distinct\n");
        } else {
            qsort(nums, 3, sizeof(int), compare);
            printf("%d\n", nums[1]);
        }
    }
    return 0;
}

