    cin.tie(NULL);
    int t;
    cin >> t;
    while (t--) {
        int nums[3];
        cin >> nums[0] >> nums[1] >> nums[2];
        if (nums[0] == nums[1] || nums[0] == nums[2] || nums[1] == nums[2]) {
